/**
 * generateCourseData.js
 * Generates a clean, valid course-data-java-fullstack.js
 * Run: node scripts/generateCourseData.js
 */
const fs = require('fs');
const path = require('path');

// ─── helpers ──────────────────────────────────────────────────────────────────
const s  = (h, t)    => ({ heading: h, text: t });
const c  = (h, code) => ({ heading: h, code });
const q  = (q, opts, ans, exp) => ({ q, opts, ans, explanation: exp || '' });
const res = (label, url) => ({ label, url });

function topic(id, title, ytId, ytTitle, ytCh, ytDur, ytDesc, sections, taskTitle, taskInstr, taskHint, resources, quizItems) {
  return {
    id, title,
    video: { youtubeId: ytId, title: ytTitle, channel: ytCh, duration: ytDur, description: ytDesc },
    content: { sections, practiceTask: { title: taskTitle, instructions: taskInstr, hint: taskHint }, resources },
    quiz: quizItems
  };
}

function week(id, title, topics, weekQuiz, projectTitle, projectDesc, projectReqs) {
  return { id, title, topics, weekQuiz, miniProject: { title: projectTitle, description: projectDesc, requirements: projectReqs } };
}

