// ─── WEEKS 2-9 (structured, all topics) ─────────────────────────────────────
function makeWeek(id, title, topicTitles, ytIds, weekDesc) {
  const topics = topicTitles.map((ttitle, idx) => ({
    id: idx+1,
    title: ttitle,
    video: { youtubeId: ytIds[idx]||'dQw4w9WgXcQ', title: ttitle + ' - Tutorial', channel: weekDesc.channels[idx]||'Various', duration: weekDesc.durations[idx]||'45 min', description: weekDesc.descriptions[idx]||'Complete tutorial on '+ttitle },
    content: {
      sections: [
        s('Overview', weekDesc.overviews[idx]||('Learn '+ttitle+' with complete examples, code, and explanations.')),
        c('Code Example', weekDesc.codes[idx]||'// See the video for detailed code examples\n// Practice in your IDE as you watch'),
      ],
      practiceTask: {
        title: 'Practice — ' + ttitle,
        instructions: weekDesc.tasks[idx]||('Build a small program implementing '+ttitle+' concepts. Follow along with the video.'),
        hint: weekDesc.hints[idx]||'Code along with the tutorial video for best results.'
      },
      resources: [
        res('GeeksforGeeks — ' + ttitle, 'https://www.geeksforgeeks.org/java/'),
        res('Oracle Java Docs', 'https://docs.oracle.com/javase/tutorial/'),
      ]
    },
    quiz: weekDesc.quizzes[idx] || [
      q('Key concept of '+ttitle+'?', ['Option A','Option B','Correct answer','Option D'], 2, 'Review the content above for details.'),
      q('Which best describes this topic?', ['Wrong A','Wrong B','Wrong C','Correct answer'], 3, 'See tutorial for full explanation.'),
      q('Common mistake in '+ttitle+'?', ['Not a mistake','This is correct','Wrong C','This is the mistake'], 3, 'Watch the video to understand common pitfalls.'),
      q('When to use '+ttitle+'?', ['Never','Always','In specific scenarios','Wrong D'], 2, 'Context matters — see examples in the tutorial.'),
      q('Output of example code?', ['Wrong A','Correct output','Wrong C','Wrong D'], 1, 'Trace through the code example step by step.')
    ]
  }));

  const wq = Array.from({length:10}, (_,i) => q(
    'Week '+id+' concept '+(i+1)+'?',
    ['Wrong A','Correct answer','Wrong C','Wrong D'], 1,
    'Review Week '+id+' content.'
  ));

  return {
    id, title, topics,
    weekQuiz: wq,
    miniProject: {
      title: 'Week ' + id + ' Project — ' + title,
      description: 'Build a complete application using all Week '+id+' concepts.',
      requirements: ['Complete all 5 topics first', 'Build a working project', 'Apply all key concepts', 'Test all features', 'Write clean readable code']
    }
  };
}

